// SPDX-License-Identifier: ISC
//! Replay of frozen dcrjson vectors generated by an in-package dump
//! test running inside dcrd's dcrjson package at release-v2.1.5.
//!
//! The dump registers a battery of dx-prefixed test commands and pins
//! the marshalled request/response bytes, error strings, one-line
//! usage text, and full generated help output.  The replay rebuilds
//! the same type descriptors and compares byte for byte.

// The battery tables mirror the Go dump rows one to one, including a
// nine-field command and literal float values such as 3.14.
#![allow(clippy::too_many_arguments)]
#![allow(clippy::approx_constant)]
#![allow(clippy::type_complexity)]

use std::collections::HashMap;

use dcroxide_dcrjson::{
    Arg, CmdInstance, GoType, GoValue, Method, RPCError, Registry, RpcId, StructField,
    UF_NOTIFICATION, UF_WEBSOCKET_ONLY, UsageFlag, decode_concatenated_hashes,
    encode_concatenated_hashes, err_rpc_internal, err_rpc_invalid_params, err_rpc_invalid_request,
    err_rpc_method_not_found, err_rpc_parse, gojson, marshal_cmd, marshal_request,
    marshal_response, new_cmd, new_request, parse_params,
};
use dcroxide_testutil::unhex;

const VECTORS: &str = include_str!("data/dcrjson_vectors.txt");

fn utf8(hex: &str) -> String {
    String::from_utf8(unhex(hex)).expect("utf8 payload")
}

// ---------------------------------------------------------------------
// Type descriptors mirroring the dump's Go test types.
// ---------------------------------------------------------------------

fn f(name: &str, typ: GoType) -> StructField {
    StructField::new(name, typ)
}

fn dx_sub() -> GoType {
    GoType::strukt(
        "dcrjson",
        "dxSub",
        vec![
            f("A", GoType::Int),
            f("B", GoType::String),
            f("C", GoType::Float64),
        ],
    )
}

fn dx_basic() -> GoType {
    GoType::strukt(
        "dcrjson",
        "dxBasicCmd",
        vec![
            f("IntF", GoType::Int),
            f("Int8F", GoType::Int8),
            f("Uint16F", GoType::Uint16),
            f("Int64F", GoType::Int64),
            f("Uint64F", GoType::Uint64),
            f("F32", GoType::Float32),
            f("F64", GoType::Float64),
            f("BoolF", GoType::Bool),
            f("StrF", GoType::String),
        ],
    )
}

fn dx_get_block() -> GoType {
    GoType::strukt(
        "dcrjson",
        "dxGetBlockCmd",
        vec![
            f("Hash", GoType::String),
            f("Verbose", GoType::Bool.ptr()).with_default("true"),
            f("VerboseTx", GoType::Bool.ptr()),
        ],
    )
}

fn dx_count() -> GoType {
    GoType::strukt("dcrjson", "dxCountCmd", vec![])
}

fn dx_opts() -> GoType {
    GoType::strukt(
        "dcrjson",
        "dxOptsCmd",
        vec![
            f("Req", GoType::String),
            f("OptInt", GoType::Int.ptr()).with_default("3"),
            f("OptStr", GoType::String.ptr()).with_default("\"def\""),
            f("OptF64", GoType::Float64.ptr()).with_default("0.1"),
            f("OptBool", GoType::Bool.ptr()),
        ],
    )
}

fn dx_nested() -> GoType {
    GoType::strukt(
        "dcrjson",
        "dxNestedCmd",
        vec![
            f("Name", GoType::String),
            f("Sub", dx_sub()),
            f("Subs", dx_sub().slice()),
            f(
                "Data",
                GoType::Map(Box::new(GoType::String), Box::new(GoType::Float64)),
            ),
            f("Arr", GoType::Array(2, Box::new(GoType::String))),
            f("Names", GoType::String.slice()),
            f("Entries", GoType::String.slice()),
            f("Addresses", GoType::String.slice()),
            f("Caps", dx_sub().ptr()).with_default("{\"a\":7,\"b\":\"x\",\"c\":2.5}"),
        ],
    )
}

fn dx_usage() -> GoType {
    GoType::strukt(
        "dcrjson",
        "dxUsageCmd",
        vec![
            f("Filter", GoType::String).with_usage("\"filter\""),
            f("Ids", GoType::Int.slice()),
            f("Verbose", GoType::Bool.ptr()).with_usage("verbose?"),
        ],
    )
}

fn dx_bytes() -> GoType {
    GoType::strukt(
        "dcrjson",
        "dxBytesCmd",
        vec![f("Data", GoType::Uint8.slice())],
    )
}

fn dx_named() -> GoType {
    GoType::strukt("dcrjson", "dxNamedCmd", vec![f("Tag", GoType::String)])
}

fn conv_cmd(name: &str, field_type: GoType) -> GoType {
    GoType::strukt("dcrjson", name, vec![f("V", field_type)])
}

fn dx_dup() -> GoType {
    GoType::strukt("dcrjson", "dxDupCmd", vec![f("A", GoType::Int)])
}

fn dx_bad_default() -> GoType {
    GoType::strukt(
        "dcrjson",
        "dxBadDefault",
        vec![f("A", GoType::Int).with_default("1")],
    )
}

fn dx_inner_result() -> GoType {
    GoType::strukt(
        "dcrjson",
        "dxInnerResult",
        vec![
            f("X", GoType::Int32).with_json_tag("x"),
            f("Y", GoType::String).with_json_tag("y"),
        ],
    )
}

fn dx_item_result() -> GoType {
    GoType::strukt(
        "dcrjson",
        "dxItemResult",
        vec![
            f("Key", GoType::String).with_json_tag("key"),
            f("Count", GoType::Int64).with_json_tag("count"),
            f("Inner", dx_inner_result()).with_json_tag("inner"),
            f("Ratio", GoType::Float64),
        ],
    )
}

fn dx_help_result() -> GoType {
    GoType::strukt(
        "dcrjson",
        "dxHelpResult",
        vec![
            f("Total", GoType::Int64).with_json_tag("total"),
            f("Flag", GoType::Bool).with_json_tag("flag"),
            f("Name", GoType::String).with_json_tag("name"),
            f("Rate", GoType::Float64).with_json_tag("rate"),
            f("Items", dx_item_result().slice()).with_json_tag("items"),
            f("Tags", GoType::String.slice()).with_json_tag("tags"),
            f("Info", dx_item_result()).with_json_tag("info"),
            f(
                "Data",
                GoType::Map(Box::new(GoType::String), Box::new(GoType::Float64)),
            )
            .with_json_tag("data"),
            f("MaybeI", GoType::Int64.ptr()).with_json_tag("maybei"),
        ],
    )
}

// Values used across marshal rows.

fn sub_value(a: i64, b: &str, c: f64) -> GoValue {
    GoValue::Struct(vec![
        GoValue::Int(a),
        GoValue::String(b.to_string()),
        GoValue::Float64(c),
    ])
}

fn basic_value(
    int_f: i64,
    i8f: i64,
    u16f: u64,
    i64f: i64,
    u64f: u64,
    f32v: f32,
    f64v: f64,
    boolf: bool,
    strf: &str,
) -> CmdInstance {
    CmdInstance::new(
        dx_basic().ptr(),
        vec![
            GoValue::Int(int_f),
            GoValue::Int(i8f),
            GoValue::Uint(u16f),
            GoValue::Int(i64f),
            GoValue::Uint(u64f),
            GoValue::Float32(f32v),
            GoValue::Float64(f64v),
            GoValue::Bool(boolf),
            GoValue::String(strf.to_string()),
        ],
    )
}

