fn check_err(
    line: &str,
    parts: &[&str],
    result: Result<impl core::fmt::Debug, dcroxide_dcrjson::DcrjsonError>,
) {
    match result {
        Ok(v) => panic!("{line}: expected error, got {v:?}"),
        Err(e) => {
            assert_eq!(e.kind.kind_name(), parts[0], "kind for {line}");
            assert_eq!(e.description, utf8(parts[1]), "description for {line}");
        }
    }
}

#[test]
fn dcrjson_vectors() {
    let mut registry = Registry::new();
    let registers = register_battery();
    let marshals = marshalcmd_battery();
    let newcmds = newcmd_battery();
    let parses = parseparams_battery();
    let helps = genhelp_battery();
    let reqs = reqjson_battery();
    let resps = respjson_battery();

    let mut counts: HashMap<&str, usize> = HashMap::new();
    let mut reg_idx = 0usize;
    let mut cmd_idx = 0usize;
    let mut new_idx = 0usize;
    let mut pp_idx = 0usize;
    let mut help_idx = 0usize;
    let mut req_idx = 0usize;
    let mut resp_idx = 0usize;

    for line in VECTORS.lines() {
        if line.is_empty() {
            continue;
        }
        let parts: Vec<&str> = line.split('|').collect();
        *counts.entry(parts[0]).or_insert(0) += 1;
        match parts[0] {
            "usageflag" => {
                let fl: u32 = parts[1].parse().unwrap();
                // The rendered flags contain '|' separators themselves.
                let want = parts[2..].join("|");
                assert_eq!(format!("{}", UsageFlag(fl)), want, "usageflag {fl}");
            }
            "register" => {
                let (label, method, typ, flags) = &registers[reg_idx];
                reg_idx += 1;
                assert_eq!(*label, parts[1], "register order for {line}");
                let result = registry.register(method, typ, *flags);
                if parts[2] == "ok" {
                    result.unwrap_or_else(|e| panic!("{line}: {e}"));
                } else {
                    check_err(line, &parts[3..], result);
                }
            }
            "regmethods" => {
                let type_name = match parts[1] {
                    "string" => "string",
                    "dxMethod" => "dcrjson.dxMethod",
                    other => panic!("unknown method type {other}"),
                };
                let methods = registry.registered_methods(type_name);
                assert_eq!(methods.join(","), parts[2], "regmethods {line}");
            }
            "reqjson" => {
                let (label, version, id, params) = &reqs[req_idx];
                req_idx += 1;
                assert_eq!(*label, parts[1], "reqjson order for {line}");
                let result = new_request(version, id, params.clone());
                if parts[2] == "ok" {
                    let req = result.unwrap_or_else(|e| panic!("{line}: {e}"));
                    assert_eq!(marshal_request(&req, "dxmethod"), utf8(parts[3]), "{line}");
                } else {
                    check_err(line, &parts[3..], result);
                }
            }
            "respjson" => {
                let (label, version, id, result_json, rpc_err) = &resps[resp_idx];
                resp_idx += 1;
                assert_eq!(*label, parts[1], "respjson order for {line}");
                let result =
                    marshal_response(version, id, result_json.as_deref(), rpc_err.as_ref());
                if parts[2] == "ok" {
                    let resp = result.unwrap_or_else(|e| panic!("{line}: {e}"));
                    assert_eq!(resp, utf8(parts[3]), "{line}");
                } else {
                    check_err(line, &parts[3..], result);
                }
            }
            "rpcerrstr" => {
                let code: i32 = parts[1].parse().unwrap();
                let message = utf8(parts[2]);
                let err = match code {
                    -32600 => err_rpc_invalid_request(),
                    -32601 => err_rpc_method_not_found(),
                    -32602 => err_rpc_invalid_params(),
                    -32603 => err_rpc_internal(),
                    -32700 => err_rpc_parse(),
                    other => panic!("unknown std error code {other}"),
                };
                assert_eq!(err.code, code, "{line}");
                assert_eq!(err.message, message, "{line}");
                assert_eq!(format!("{err}"), utf8(parts[3]), "{line}");
            }
            "marshalcmd" => {
                let (label, id, cmd) = &marshals[cmd_idx];
                cmd_idx += 1;
                assert_eq!(*label, parts[1], "marshalcmd order for {line}");
                let result = marshal_cmd(&registry, "1.0", id, cmd);
                if parts[2] == "ok" {
                    assert_eq!(result.unwrap(), utf8(parts[3]), "{line}");
                } else {
                    check_err(line, &parts[3..], result);
                }
            }
            "newcmd" => {
                let (label, method, args) = &newcmds[new_idx];
                new_idx += 1;
                assert_eq!(*label, parts[1], "newcmd order for {line}");
                let result = new_cmd(&registry, &Method::plain(method), args)
                    .and_then(|cmd| marshal_cmd(&registry, "1.0", &RpcId::Int(1), &cmd));
                if parts[2] == "ok" {
                    assert_eq!(result.unwrap(), utf8(parts[3]), "{line}");
                } else {
                    check_err(line, &parts[3..], result);
                }
            }
            "parseparams" => {
                let (label, method, params) = &parses[pp_idx];
                pp_idx += 1;
                assert_eq!(*label, parts[1], "parseparams order for {line}");
                let result = parse_params(&registry, &Method::plain(method), params)
                    .and_then(|cmd| marshal_cmd(&registry, "1.0", &RpcId::Int(1), &cmd));
                if parts[2] == "ok" {
                    assert_eq!(result.unwrap(), utf8(parts[3]), "{line}");
                } else {
                    check_err(line, &parts[3..], result);
                }
            }
            "usagetext" => {
                let result = registry.method_usage_text(&Method::plain(parts[1]));
                if parts.len() == 3 {
                    assert_eq!(result.unwrap(), utf8(parts[2]), "{line}");
                } else {
                    check_err(line, &parts[3..], result);
                }
            }
            "cmdmethod" => {
                if parts[2] == "ok" {
                    let method = registry.cmd_method(&dx_get_block().ptr()).unwrap();
                    assert_eq!(method, parts[3], "{line}");
                } else {
                    check_err(line, &parts[3..], registry.cmd_method(&GoType::Int.ptr()));
                }
            }
            "methodflags" => {
                let method = match parts[1] {
                    "dxnamed" => Method::typed("dcrjson.dxMethod", "dxnamed"),
                    "dxnamed-plainstring" => Method::plain("dxnamed"),
                    other => Method::plain(other),
                };
                let result = registry.method_usage_flags(&method);
                if parts[2] == "ok" {
                    let want: u32 = parts[3].parse().unwrap();
                    assert_eq!(result.unwrap().0, want, "{line}");
                } else {
                    check_err(line, &parts[3..], result);
                }
            }
            "genhelp" => {
                let (label, method, descs, results) = &helps[help_idx];
                help_idx += 1;
                assert_eq!(*label, parts[1], "genhelp order for {line}");
                let descs: HashMap<String, String> = descs
                    .iter()
                    .map(|(k, v)| (k.to_string(), v.to_string()))
                    .collect();
                let (help, err) = registry.generate_help(method, &descs, results);
                if parts[2] == "ok" {
                    assert!(err.is_none(), "{line}: unexpected error {err:?}");
                    assert_eq!(help, utf8(parts[3]), "{line}");
                } else {
                    // "partial": the help text (possibly empty) plus
                    // the error kind and description.
                    let err = err.unwrap_or_else(|| panic!("{line}: expected error"));
                    assert_eq!(help, utf8(parts[3]), "{line}");
                    assert_eq!(err.kind.kind_name(), parts[4], "{line}");
                    assert_eq!(err.description, utf8(parts[5]), "{line}");
                }
            }
            "concat" => {
                replay_concat(line, &parts);
            }
            other => panic!("unknown vector op {other}"),
        }
    }

    // Every battery must be fully consumed and the frozen row counts
    // must match.
    assert_eq!(reg_idx, registers.len());
    assert_eq!(cmd_idx, marshals.len());
    assert_eq!(new_idx, newcmds.len());
    assert_eq!(pp_idx, parses.len());
    assert_eq!(help_idx, helps.len());
    assert_eq!(req_idx, reqs.len());
    assert_eq!(resp_idx, resps.len());
    let expected: &[(&str, usize)] = &[
        ("usageflag", 12),
        ("register", 39),
        ("regmethods", 2),
        ("reqjson", 9),
        ("respjson", 11),
        ("rpcerrstr", 5),
        ("marshalcmd", 15),
        ("newcmd", 50),
        ("parseparams", 34),
        ("usagetext", 13),
        ("cmdmethod", 2),
        ("methodflags", 3),
        ("genhelp", 12),
        ("concat", 10),
    ];
    for (op, want) in expected {
        assert_eq!(counts.get(op), Some(want), "row count for {op}");
    }
}

fn mkhash(seed: u8) -> dcroxide_chainhash::Hash {
    let mut h = [0u8; 32];
    for (i, b) in h.iter_mut().enumerate() {
        *b = seed.wrapping_add(i as u8);
    }
    dcroxide_chainhash::Hash(h)
}

fn replay_concat(line: &str, parts: &[&str]) {
    let h1 = mkhash(0);
    let h2 = mkhash(0x40);
    let h3 = mkhash(0x80);
    let enc = |hashes: &[dcroxide_chainhash::Hash]| encode_concatenated_hashes(hashes);
    match parts[1] {
        "enc0" => assert_eq!(enc(&[]), parts[2], "{line}"),
        "enc1" => assert_eq!(enc(&[h1]), parts[2], "{line}"),
        "enc3" => assert_eq!(enc(&[h1, h2, h3]), parts[2], "{line}"),
        label => {
            let input = match label {
                "dec-empty" => String::new(),
                "dec-one" => enc(&[h1]),
                "dec-three" => enc(&[h3, h1, h2]),
                "dec-upper" => enc(&[h2]).to_uppercase(),
                "dec-odd" => "abcd12".to_string(),
                "dec-badhex" => "zz".repeat(32),
                "dec-badhex-second" => format!("{}{}", enc(&[h1]), "zz".repeat(32)),
                other => panic!("unknown concat label {other}"),
            };
            match decode_concatenated_hashes(&input) {
                Ok(hashes) => {
                    assert_eq!(parts[2], "ok", "{line}");
                    let joined: Vec<String> = hashes
                        .iter()
                        .map(|h| h.as_bytes().iter().map(|b| format!("{b:02x}")).collect())
                        .collect();
                    assert_eq!(joined.join(","), parts[3], "{line}");
                }
                Err(rpc_err) => {
                    assert_eq!(parts[2], "err", "{line}");
                    let code: i32 = parts[3].parse().unwrap();
                    assert_eq!(rpc_err.code, code, "{line}");
                    assert_eq!(rpc_err.message, utf8(parts[4]), "{line}");
                }
            }
        }
    }
}
